/// BTTabs — tab strip molecule (Figma Tabs 434:6135 · TabItem 434:5262).
library;

export 'tabs.types.dart';
export 'tabs.widget.dart';

// Public types for [BTTabs].
//
// Sliced from Figma Tabs 434:6135 · TabItem 434:5262.
// Cross-framework parity: prop names match Vue/React BTTabsProps exactly.

import 'package:flutter/foundation.dart';

/// Visual style of the tab strip.
///
///   [segmented] — pill-style tray with gray background.
///                 Active tab has filled primary background + white text.
///   [line]      — flat row, no tray background.
///                 Active tab has primary underline border + primary text.
enum BTTabsVariant { segmented, line }

/// Configuration for the [BTTabs] widget.
///
/// All fields mirror the Vue/React [BTTabsProps] for cross-framework parity.
// ignore: avoid_classes_with_only_static_members — intentionally a data class
// (keeping separate from BTTabItem to match web types structure)

/// Data for a single tab item.
class BTTabItem {
  const BTTabItem({
    required this.label,
    this.disabled = false,
  });

  /// Label text displayed in the tab.
  final String label;

  /// When true, the tab is not interactive. Defaults to false.
  final bool disabled;
}

/// Programmatic controller for [BTTabs].
///
/// Works analogously to Flutter's [TabController], allowing parent widgets to
/// drive tab selection and listen to changes programmatically.
///
/// Must be [dispose]d when no longer needed (typically in [State.dispose]).
///
/// ## Usage:
/// ```dart
/// class _MyWidgetState extends State<MyWidget> {
///   late final BTTabsController _tabController;
///
///   @override
///   void initState() {
///     super.initState();
///     _tabController = BTTabsController(length: 3);
///   }
///
///   @override
///   void dispose() {
///     _tabController.dispose();
///     super.dispose();
///   }
///
///   @override
///   Widget build(BuildContext context) => Column(
///     children: [
///       BTTabs(controller: _tabController, tabs: const [...]),
///       ElevatedButton(
///         onPressed: () => _tabController.animateTo(2),
///         child: const Text('Jump to tab 3'),
///       ),
///     ],
///   );
/// }
/// ```
class BTTabsController extends ChangeNotifier {
  /// Creates a [BTTabsController] for a tab strip with [length] tabs.
  ///
  /// [initialIndex] defaults to `0`.
  BTTabsController({
    required this.length,
    int initialIndex = 0,
  })  : assert(length > 0, 'length must be > 0'),
        assert(
          initialIndex >= 0 && initialIndex < length,
          'initialIndex must be in [0, length)',
        ),
        _index = initialIndex,
        _previousIndex = initialIndex;

  /// Total number of tabs. Must match the [BTTabs.tabs] list length.
  final int length;

  int _index;
  int _previousIndex;

  /// Zero-based index of the currently selected tab.
  int get index => _index;

  /// Zero-based index of the previously selected tab.
  int get previousIndex => _previousIndex;

  /// Selects tab at [value] and notifies listeners.
  ///
  /// No-op if [value] equals the current [index].
  void animateTo(int value) {
    assert(
      value >= 0 && value < length,
      'animateTo($value) out of range [0, $length)',
    );
    if (_index == value) return;
    _previousIndex = _index;
    _index = value;
    notifyListeners();
  }
}

/// BTTabs — tab strip molecule.
///
/// Sliced from Figma Tabs 434:6135 · TabItem 434:5262.
/// Two variants: 'segmented' (pill tray) · 'line' (underline).
///
/// Animation: sliding pill / underline indicator.
/// The active tab's background (segmented) or underline (line) slides
/// smoothly to the newly-selected position — no opacity toggling.
///
/// `scrollable`: horizontally scrolls and auto-centers the active tab.
///
/// ## Usage:
/// ```dart
/// // Segmented (controlled via activeIndex)
/// BTTabs(
///   variant: BTTabsVariant.segmented,
///   tabs: const [
///     BTTabItem(label: 'Overview'),
///     BTTabItem(label: 'Details'),
///     BTTabItem(label: 'History'),
///   ],
///   activeIndex: _activeIndex,
///   onActiveIndexChange: (i) => setState(() => _activeIndex = i),
/// );
///
/// // Programmatic controller pattern
/// BTTabs(
///   controller: _tabController,
///   tabs: const [...],
/// );
///
/// // Scrollable line with icons
/// BTTabs(
///   variant: BTTabsVariant.line,
///   scrollable: true,
///   tabs: manyTabs,
///   activeIndex: _activeIndex,
///   onActiveIndexChange: (i) => setState(() => _activeIndex = i),
///   leadingIconBuilder: (i) =>
///       Icon(i == 0 ? Icons.list : Icons.grid_view, size: 16),
/// );
/// ```
library;

import 'package:btech_tokens/btech_tokens.dart';
import 'package:btech_ui/src/components/molecules/tabs/tabs.types.dart';
import 'package:flutter/material.dart';

/// BTTabs widget — see file header for usage.
class BTTabs extends StatefulWidget {
  const BTTabs({
    required this.tabs,
    this.variant = BTTabsVariant.segmented,
    this.activeIndex = 0,
    this.scrollable = false,
    this.onActiveIndexChange,
    this.leadingIconBuilder,
    this.trailingIconBuilder,
    this.controller,
    super.key,
  });

  /// Visual style — [BTTabsVariant.segmented] or [BTTabsVariant.line].
  final BTTabsVariant variant;

  /// Ordered list of tab descriptors.
  final List<BTTabItem> tabs;

  /// Zero-based index of the currently active tab.
  ///
  /// Ignored when [controller] is set — the controller's index takes precedence.
  final int activeIndex;

  /// When `true`, the strip is horizontally scrollable and auto-centers
  /// the active tab on each selection.
  final bool scrollable;

  /// Called when the user selects a tab. Receives the new active index.
  final ValueChanged<int>? onActiveIndexChange;

  /// Optional builder for a leading icon in each tab.
  final Widget? Function(int index)? leadingIconBuilder;

  /// Optional builder for a trailing icon in each tab.
  final Widget? Function(int index)? trailingIconBuilder;

  /// Optional programmatic controller. When provided, overrides [activeIndex].
  ///
  /// The widget listens to the controller and rebuilds whenever [BTTabsController.animateTo]
  /// is called. The caller is responsible for [BTTabsController.dispose].
  final BTTabsController? controller;

  @override
  State<BTTabs> createState() => _BTTabsState();
}

class _BTTabsState extends State<BTTabs> {
  // Keys for measuring each tab button's position/size
  late List<GlobalKey> _tabKeys;

  // Key for the inner layout container (Stack), used as coordinate anchor
  final _stackKey = GlobalKey();

  // Sliding indicator geometry (relative to _stackKey)
  double _indicatorLeft = 0;
  double _indicatorWidth = 0;

  // Suppresses AnimatedPositioned on the very first paint
  bool _isReady = false;

  ScrollController? _scrollController;

  @override
  void initState() {
    super.initState();
    _initKeys();
    if (widget.scrollable) {
      _scrollController = ScrollController();
    }
    if (widget.controller != null) {
      widget.controller!.addListener(_onControllerChange);
    }
    // Position indicator after first frame
    WidgetsBinding.instance.addPostFrameCallback((_) => _updateIndicator());
  }

  @override
  void didUpdateWidget(BTTabs old) {
    super.didUpdateWidget(old);
    if (old.tabs.length != widget.tabs.length) {
      _initKeys();
    }
    // Handle controller swap
    if (old.controller != widget.controller) {
      old.controller?.removeListener(_onControllerChange);
      widget.controller?.addListener(_onControllerChange);
    }
    if (old.activeIndex != widget.activeIndex ||
        old.variant != widget.variant ||
        old.controller?.index != widget.controller?.index) {
      WidgetsBinding.instance.addPostFrameCallback((_) => _updateIndicator());
    }
  }

  @override
  void dispose() {
    widget.controller?.removeListener(_onControllerChange);
    _scrollController?.dispose();
    super.dispose();
  }

  void _onControllerChange() {
    setState(() {});
    WidgetsBinding.instance.addPostFrameCallback((_) => _updateIndicator());
  }

  void _initKeys() {
    _tabKeys = List.generate(widget.tabs.length, (_) => GlobalKey());
  }

  /// Returns the effective active index: controller index takes precedence over activeIndex.
  int get _effectiveIndex => widget.controller?.index ?? widget.activeIndex;

  void _updateIndicator() {
    if (!mounted) return;

    final stackBox =
        _stackKey.currentContext?.findRenderObject() as RenderBox?;
    if (stackBox == null) return;

    final tabKey = _tabKeys[_effectiveIndex];
    final tabBox = tabKey.currentContext?.findRenderObject() as RenderBox?;
    if (tabBox == null) return;

    // Position of the tab relative to the stack (our coordinate anchor)
    final offset = tabBox.localToGlobal(Offset.zero, ancestor: stackBox);

    setState(() {
      _indicatorLeft = offset.dx;
      _indicatorWidth = tabBox.size.width;
      _isReady = true;
    });

    _scrollToCenter(tabBox, stackBox);
  }

  void _scrollToCenter(RenderBox tabBox, RenderBox stackBox) {
    final sc = _scrollController;
    if (!widget.scrollable || sc == null || !sc.hasClients) return;

    final tabOffset = tabBox.localToGlobal(Offset.zero, ancestor: stackBox);
    final tabCenter = tabOffset.dx + tabBox.size.width / 2;
    final viewportCenter = sc.position.viewportDimension / 2;
    final target = (tabCenter - viewportCenter)
        .clamp(0.0, sc.position.maxScrollExtent);

    sc.animateTo(
      target,
      duration: const Duration(milliseconds: 280),
      curve: Curves.easeInOut,
    );
  }

  void _select(int index) {
    if (widget.tabs[index].disabled) return;
    widget.controller?.animateTo(index);
    widget.onActiveIndexChange?.call(index);
  }

  @override
  Widget build(BuildContext context) {
    return switch (widget.variant) {
      BTTabsVariant.segmented => _buildSegmented(context),
      BTTabsVariant.line => _buildLine(context),
    };
  }

  // ── Segmented ─────────────────────────────────────────────────────────────

  Widget _buildSegmented(BuildContext context) {
    final content = Container(
      height: 40.0,
      padding: EdgeInsets.all(4.0),
      decoration: BoxDecoration(
        color: context.btColor.bg.secondary,
        borderRadius: BorderRadius.circular(context.btRadius.md),
      ),
      child: Stack(
        key: _stackKey,
        clipBehavior: Clip.none,
        children: [
          // Sliding pill indicator (behind tab labels)
          if (_isReady)
            AnimatedPositioned(
              duration: const Duration(milliseconds: 220),
              curve: Curves.easeInOut,
              left: _indicatorLeft,
              top: 0,
              width: _indicatorWidth,
              height: 32.0,
              child: DecoratedBox(
                decoration: BoxDecoration(
                  color: context.btColor.brand.primary,
                  borderRadius:
                      BorderRadius.circular(context.btRadius.sm),
                ),
              ),
            ),
          // Tab buttons (on top of indicator via Stack ordering).
          // scrollable: tabs are intrinsic-width — Expanded would require
          // a bounded constraint which the horizontal SCSV cannot provide.
          // non-scrollable: Expanded fills available width evenly.
          if (widget.scrollable)
            Row(
              mainAxisSize: MainAxisSize.min,
              children: [
                for (var i = 0; i < widget.tabs.length; i++)
                  _buildTabButton(context, i),
              ],
            )
          else
            Row(
              children: [
                for (var i = 0; i < widget.tabs.length; i++)
                  Expanded(child: _buildTabButton(context, i)),
              ],
            ),
        ],
      ),
    );

    return widget.scrollable
        ? SingleChildScrollView(
            controller: _scrollController,
            scrollDirection: Axis.horizontal,
            // IntrinsicWidth lets the Container size to its tab content
            // instead of stretching to the SCSV's unbounded constraint.
            child: IntrinsicWidth(child: content),
          )
        : content;
  }

  // ── Line ──────────────────────────────────────────────────────────────────

  Widget _buildLine(BuildContext context) {
    final row = Row(
      mainAxisSize: MainAxisSize.min,
      children: [
        for (var i = 0; i < widget.tabs.length; i++) ...[
          if (i > 0) const SizedBox(width: 24.0),
          _buildTabButton(context, i),
        ],
      ],
    );

    final content = Stack(
      key: _stackKey,
      alignment: Alignment.bottomLeft,
      children: [
        row,
        // Sliding underline indicator (2px, at the very bottom)
        if (_isReady)
          AnimatedPositioned(
            duration: const Duration(milliseconds: 220),
            curve: Curves.easeInOut,
            left: _indicatorLeft,
            bottom: 0,
            width: _indicatorWidth,
            height: 2.0,
            child: ColoredBox(color: context.btColor.brand.primary),
          ),
      ],
    );

    return widget.scrollable
        ? SingleChildScrollView(
            controller: _scrollController,
            scrollDirection: Axis.horizontal,
            // IntrinsicWidth lets the Stack size to its Row content
            // instead of stretching to the SCSV's unbounded constraint.
            child: IntrinsicWidth(child: content),
          )
        : content;
  }

  // ── Shared tab button ─────────────────────────────────────────────────────

  Widget _buildTabButton(BuildContext context, int i) {
    final tab = widget.tabs[i];
    final isActive = i == _effectiveIndex;
    final isSegmented = widget.variant == BTTabsVariant.segmented;
    final activeColor = context.btColor.brand.primary;
    final inactiveColor = context.btColor.text.secondary;

    final textColor = switch ((isSegmented, isActive)) {
      (true, true)   => context.btColor.text.inverse,
      (false, true)  => activeColor,
      _              => inactiveColor,
    };

    return GestureDetector(
      key: _tabKeys[i],
      // opaque: entire cell area is tappable, not just the text pixels.
      // deferToChild (default) only hits where a child actually paints,
      // so the empty area around the label would be a dead zone.
      behavior: HitTestBehavior.opaque,
      onTap: tab.disabled ? null : () => _select(i),
      child: Opacity(
        opacity: tab.disabled ? 0.4 : 1.0,
        child: Container(
          height: 32.0,
          alignment: Alignment.center,
          padding: isSegmented
              ? const EdgeInsets.symmetric(horizontal: 12.0, vertical: 8.0)
              : const EdgeInsets.symmetric(vertical: 8.0),
          child: _TabContent(
            label: tab.label,
            textColor: textColor,
            leadingIcon: widget.leadingIconBuilder?.call(i),
            trailingIcon: widget.trailingIconBuilder?.call(i),
          ),
        ),
      ),
    );
  }
}

// ── Private content widget ───────────────────────────────────────────────────

class _TabContent extends StatelessWidget {
  const _TabContent({
    required this.label,
    required this.textColor,
    this.leadingIcon,
    this.trailingIcon,
  });

  final String label;
  final Color textColor;
  final Widget? leadingIcon;
  final Widget? trailingIcon;

  @override
  Widget build(BuildContext context) {
    return Row(
      mainAxisSize: MainAxisSize.min,
      children: [
        if (leadingIcon != null) ...[
          SizedBox(
            width: 16.0,
            height: 16.0,
            child: IconTheme(
              data: IconThemeData(color: textColor, size: 16),
              child: leadingIcon!,
            ),
          ),
          SizedBox(width: 4.0),
        ],
        AnimatedDefaultTextStyle(
          duration: const Duration(milliseconds: 220),
          curve: Curves.easeInOut,
          style: TextStyle(
            color: textColor,
            fontSize: 14.0,
            fontWeight: FontWeight.w500,
            height: 16 / 14,
            letterSpacing: 0,
          ),
          child: Text(label),
        ),
        if (trailingIcon != null) ...[
          SizedBox(width: 4.0),
          SizedBox(
            width: 16.0,
            height: 16.0,
            child: IconTheme(
              data: IconThemeData(color: textColor, size: 16),
              child: trailingIcon!,
            ),
          ),
        ],
      ],
    );
  }
}
